"narrativeArc": {
  "_description": "Recommended slide sequence for a discovery-style LinkedIn carousel (6-10 slides).",
  "guidelines": [
    "6-8 slides is the sweet spot. Under 5 feels thin, over 10 loses attention.",
    "Every slide must earn its place — if it doesn't add new information, cut it.",
    "Alternate between text-heavy and visual slides for rhythm.",
    "The 'discovery journey' tone: honest about failures, specific about what you tried, generous with what you learned."
  ],
  "structure": [
    {
      "position": 1,
      "purpose": "Hook — stop the scroll",
      "template": "cover"
    },
    {
      "position": 2,
      "purpose": "Context — what you were building",
      "template": "setup"
    },
    {
      "position": "3-4",
      "purpose": "The problem — show don't tell",
      "template": "comparison OR category-grid"
    },
    {
      "position": "4-5",
      "purpose": "The pattern — why it keeps happening",
      "template": "diagram OR stat-highlight"
    },
    {
      "position": "5-6",
      "purpose": "The fix — what you discovered",
      "template": "solution"
    },
    {
      "position": "6-7",
      "purpose": "The difference — tangible improvement",
      "template": "before-after"
    },
    {
      "position": "last",
      "purpose": "Key lessons + engagement CTA",
      "template": "takeaway"
    }
  ]
},
